Here's how to test `DataFetcher` with proper timeout and cancellation handling in MSTest 3.x+:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    private static DataFetcher CreateFetcher(HttpMessageHandler handler)
        => new(new HttpClient(handler));

    // --- Happy path ---

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        var handler = new FakeHandler(new HttpResponseMessage
        {
            StatusCode = HttpStatusCode.OK,
            Content = new StringContent("hello"),
        });
        var fetcher = CreateFetcher(handler);

        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("hello", result);
    }

    // --- Error status code ---

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler(new HttpResponseMessage(HttpStatusCode.NotFound));
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // --- Cancellation ---

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_WhenCancelled_ThrowsOperationCanceled()
    {
        // Handler that delays long enough for cancellation to fire
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(30), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = CreateFetcher(handler);

        using var cts = new CancellationTokenSource(TimeSpan.FromMilliseconds(50));

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    // --- Timeout via TestContext.CancellationToken ---

    [TestMethod]
    [Timeout(500)]
    public async Task FetchAsync_ExceedsTimeout_IsCancelledByFramework()
    {
        // Simulate a slow server — MSTest's [Timeout] will cancel via
        // TestContext.CancellationToken before the delay completes
        var handler = new FakeHandler(async ct =>
        {
            await Task.Delay(TimeSpan.FromSeconds(60), ct);
            return new HttpResponseMessage(HttpStatusCode.OK);
        });
        var fetcher = CreateFetcher(handler);

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync(
                "https://example.com", _testContext.CancellationToken));
    }

    // --- Minimal fake handler (no mocking library needed) ---

    private sealed class FakeHandler : HttpMessageHandler
    {
        private readonly Func<CancellationToken, Task<HttpResponseMessage>> _factory;

        public FakeHandler(HttpResponseMessage response)
            : this(_ => Task.FromResult(response)) { }

        public FakeHandler(Func<CancellationToken, Task<HttpResponseMessage>> factory)
            => _factory = factory;

        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
            => _factory(cancellationToken);
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `[Timeout] + _testContext.CancellationToken` | Framework cancels cooperatively on timeout |
| `Assert.ThrowsExactlyAsync<T>` | Replaces `[ExpectedException]`, lets you inspect the exception |
| `sealed` test class + `sealed` handler | Performance best practice |
| Fake `HttpMessageHandler` | Avoids real HTTP; gives full control over responses and delays |

The critical distinction: the **cancellation test** uses its own `CancellationTokenSource` to verify your code honors caller-provided tokens, while the **timeout test** relies on `_testContext.CancellationToken` so MSTest's `[Timeout]` attribute drives the cancellation automatically.
